let multilineStringDimensionArr = [];
let multilineStringMarketplaceArr = [];
let dimensionArr = page.variables.filteredConfigValues;

dimensionArr.forEach(val => {
  let multilineStringDimension = "";
  let multilineStringMarketplace = "";
  val.dimensions.forEach((temp) => {
    if(temp.dimension_name.includes("LEGACY_")) {
      multilineStringMarketplace = `<b>${temp.dimension_name}</b>: ${temp[temp.value]}</br>` + multilineStringMarketplace;
    }
    else {
      multilineStringDimension += `${temp.dimension_name}: ${temp[temp.value]}\n`;
    }
  });
  multilineStringDimensionArr.push(multilineStringDimension);
multilineStringMarketplaceArr.push(multilineStringMarketplace);
});
